/**
 * Implements a Min Priority Queue for Dijkstra's algorithm.
 * Stores elements as [distance, node].
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Comparison function: compares based on distance (index 0)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this._compare(index, parentIndex)) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Check left child
            if (leftChildIndex <= lastIndex && this._compare(leftChildIndex, smallest)) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && this._compare(rightChildIndex, smallest)) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                this._swap(index, smallest);
                index = smallest;
            } else {
                break;
            }
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return min;
    }
}


/**
 * Runs Dijkstra's algorithm from a single start node.
 * @param {number} N - Number of nodes.
 * @param {Array<Array<{v: number, weight: number}>>} graph - Adjacency list representation of the graph.
 * @param {number} startNode - The starting node.
 * @returns {Array<number>} Array of shortest distances from startNode to all other nodes.
 */
function dijkstra(N, graph, startNode) {
    const INF = Number.MAX_SAFE_INTEGER;
    const dist = new Array(N).fill(INF);

    // Priority Queue stores [distance, node]
    const pq = new MinPriorityQueue();

    dist[startNode] = 0;
    pq.enqueue([0, startNode]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.dequeue();

        if (d > dist[u]) {
            continue;
        }

        for (const edge of graph[u] || []) {
            const v = edge.v;
            const weight = edge.weight;

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.enqueue([dist[v], v]);
            }
        }
    }
    return dist;
}


function solve(n, prices, roads) {
    // Initialize graph adjacency lists for Empty (E) and Full (F) travel
    const graphE = Array(n).fill(0).map(() => []);
    const graphF = Array(n).fill(0).map(() => []);

    // 1. Build the graphs
    for (const road of roads) {
        const [u, v, cost, tax] = road;

        // Empty Travel Graph (Weights = cost)
        // Bidirectional
        graphE[u].push({ v: v, weight: cost });
        graphE[v].push({ v: u, weight: cost });

        // Full Travel Graph (Weights = cost * tax)
        const fullCost = cost * tax;
        // Bidirectional
        graphF[u].push({ v: v, weight: fullCost });
        graphF[v].push({ v: u, weight: fullCost });
    }

    // 2. Calculate Shortest Path Matrices

    // SE[i][j] = D_empty(i, j)
    const SE = [];
    for (let i = 0; i < n; i++) {
        SE.push(dijkstra(n, graphE, i));
    }

    // SF[j][i] = D_full(j, i)
    // We run Dijkstra from j on graphF, so the resulting distance array SF_j contains SF[j][i] at index i.
    const SF_sources = [];
    for (let j = 0; j < n; j++) {
        SF_sources.push(dijkstra(n, graphF, j));
    }

    // 3. Compute the minimum cost for each shop i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i. Cost = prices[i].
        let minCost = prices[i]; 

        // Option 2: Travel i -> j (empty), buy at j, travel j -> i (full).
        for (let j = 0; j < n; j++) {
            // D_empty(i, j) is SE[i][j]
            const emptyTravelCost = SE[i][j];

            // D_full(j, i) is the distance from source j to destination i in graphF.
            // SF_sources[j] is the distance array from j. SF_sources[j][i] is D_full(j, i).
            const fullTravelCost = SF_sources[j][i];

            // Check for unreachable paths (INF)
            if (emptyTravelCost === Number.MAX_SAFE_INTEGER || fullTravelCost === Number.MAX_SAFE_INTEGER) {
                continue; 
            }

            // Total cost = Travel(i->j) + Travel(j->i) + Buy(j)
            const totalCost = emptyTravelCost + fullTravelCost + prices[j];

            if (totalCost < minCost) {
                minCost = totalCost;
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

