using namespace std;

// Define a large constant for infinity, suitable for long long calculations
constexpr long long INF = numeric_limits<long long>::max();

// Structure to represent an edge
struct Edge {
    int to;
    long long weight;
};

/**
 * Dijkstra's algorithm implementation.
 * @param N Number of nodes.
 * @param graph Adjacency list representation of the graph.
 * @param startNode The starting node.
 * @return Array of shortest distances from startNode to all other nodes.
 */
vector<long long> dijkstra(int N, const vector<vector<Edge>>& graph, int startNode) {
    // dist[i] stores the shortest distance from startNode to i
    vector<long long> dist(N, INF);

    // Min-priority queue stores pairs: {distance, node}
    // We use greater<> to create a min-heap based on distance (the first element)
    using P = pair<long long, int>; // {distance, node}
    priority_queue<P, vector<P>, greater<P>> pq;

    dist[startNode] = 0;
    pq.push({0, startNode});

    while (!pq.empty()) {
        long long d = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        // Optimization: if we found a shorter path already, skip
        if (d > dist[u]) {
            continue;
        }

        for (const auto& edge : graph[u]) {
            int v = edge.to;
            long long weight = edge.weight;

            if (dist[u] != INF && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

