        long long tax = road[3];

        // G_E (Empty Travel): weight = cost
        // Bidirectional
        graphE[u].push_back({v, cost});
        graphE[v].push_back({u, cost});

        // G_F (Full Travel): weight = cost * tax
        // Bidirectional
        long long fullCost = cost * tax;
        graphF[u].push_back({v, fullCost});
        graphF[v].push_back({u, fullCost});
    }

    // 3. Calculate Shortest Path Matrices

    // SE[i][j] = D_empty(i, j)
    vector<vector<long long>> SE(N, vector<long long>(N));
    for (int i = 0; i < N; ++i) {
        vector<long long> dist_i = dijkstra(N, graphE, i);
        for(int j=0; j<N; ++j) {
            SE[i][j] = dist_i[j];
        }
    }

    // SF[j][i] = D_full(j, i). Since graphs are undirected, this is the same as D_full(i, j).
    // We run Dijkstra from source j on G_F, resulting in distances D_full(j, *).
    vector<vector<long long>> SF(N, vector<long long>(N));
    for (int j = 0; j < N; ++j) {
        vector<long long> dist_j = dijkstra(N, graphF, j);
        for(int i=0; i<N; ++i) {
            SF[j][i] = dist_j[i];
        }
    }

    // 4. Compute the minimum cost for each shop i
    vector<long long> ans(N);

    for (int i = 0; i < N; ++i) {
        // Option 1: Buy directly at i.
        long long minCost = prices[i]; 

        // Option 2: Travel i -> j (empty), buy at j, travel j -> i (full).
        for (int j = 0; j < N; ++j) {
            // D_empty(i, j)
            long long emptyTravelCost = SE[i][j];

            // D_full(j, i)
            long long fullTravelCost = SF[j][i];

            // Check for unreachable paths (INF)
            if (emptyTravelCost == INF || fullTravelCost == INF) {
                continue; 
            }

            // Total cost = Travel(i->j) + Travel(j->i) + Buy(j)
            // Ensure calculation doesn't overflow before comparison if we were using smaller types, 
            // but since all components are long long, the sum fits.
            long long totalCost = emptyTravelCost + fullTravelCost + prices[j];

            if (totalCost < minCost) {
                minCost = totalCost;
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

