using namespace std;

// Define a large value for infinity, ensuring it doesn't overflow when added to other costs
const long long INF = numeric_limits<long long>::max() / 2;

// Edge structure
struct Edge {
    int to;
    long long weight;
};

// Type definition for the graph adjacency list
using Graph = vector<vector<Edge>>;

/**
 * Implements Dijkstra's algorithm from a single start node.
 * @param N Number of nodes.
 * @param graph Adjacency list representation of the graph.
 * @param startNode The starting node.
 * @returns A vector of shortest distances from startNode to all other nodes.
 */
