    // dist[i] stores the shortest distance from startNode to i
    vector<long long> dist(N, INF);

    // Priority Queue stores {distance, node}. We use std::greater to make it a Min-Heap.
    // Pair format: {distance, node_index}
    using P = pair<long long, int>;
    priority_queue<P, vector<P>, greater<P>> pq;

    dist[startNode] = 0;
    pq.push({0, startNode});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();

        if (d > dist[u]) {
            continue;
        }

